css:
.wrapper-exec-kpi-band {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  --on-accent: var(--button-primary-text-color, #0B0B0D);
  container-type: inline-size;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
}
.wrapper-exec-kpi-band .kpi-band { width: 100%; }
.wrapper-exec-kpi-band .kpis {
  display: grid;
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: 14px;
}
.wrapper-exec-kpi-band .kpi {
  position: relative;
  min-width: 0;
  display: flex;
  flex-direction: column;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 16px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  transition: transform .15s ease, border-color .15s ease, background .15s ease, box-shadow .15s ease;
}
.wrapper-exec-kpi-band .kpi:hover {
  transform: translateY(-2px);
  background: var(--surface-raised);
  border-color: color-mix(in srgb, var(--accent) 35%, var(--line));
}
.wrapper-exec-kpi-band .kpi:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}
.wrapper-exec-kpi-band .kpi .label {
  display: flex;
  align-items: center;
  min-width: 0;
  overflow-wrap: anywhere;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--muted);
}
.wrapper-exec-kpi-band .kpi .label::before {
  content: "";
  display: inline-block;
  flex: 0 0 auto;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  margin-right: 8px;
  background: var(--accent);
}
.wrapper-exec-kpi-band .kpi .value {
  min-width: 0;
  overflow-wrap: anywhere;
  font: 800 26px/1.1 var(--font-stack-primary, 'Inter', system-ui);
  letter-spacing: -.01em;
  font-variant-numeric: tabular-nums;
  color: var(--ink);
  margin-top: 8px;
}
.wrapper-exec-kpi-band .kpi .ctx {
  min-width: 0;
  overflow-wrap: anywhere;
  font: 600 11px/1.3 var(--font-stack-primary, 'Inter', system-ui);
  color: var(--muted);
  margin-top: 5px;
  font-variant-numeric: tabular-nums;
}
.wrapper-exec-kpi-band .kpi:first-child {
  background: linear-gradient(135deg, var(--accent), var(--accent-2));
  border-color: transparent;
  box-shadow: 0 6px 18px rgba(0,0,0,.5), 0 0 24px -8px color-mix(in srgb, var(--accent) 55%, transparent);
}
.wrapper-exec-kpi-band .kpi:first-child .label,
.wrapper-exec-kpi-band .kpi:first-child .value,
.wrapper-exec-kpi-band .kpi:first-child .ctx {
  color: var(--on-accent);
}
.wrapper-exec-kpi-band .kpi:first-child .label { opacity: .82; }
.wrapper-exec-kpi-band .kpi:first-child .ctx { opacity: .8; }
.wrapper-exec-kpi-band .kpi:first-child .label::before {
  background: var(--on-accent);
}
.wrapper-exec-kpi-band .kpi:first-child:hover {
  background: linear-gradient(135deg, var(--accent), var(--accent-2));
  border-color: transparent;
  box-shadow: 0 8px 22px rgba(0,0,0,.55), 0 0 30px -6px color-mix(in srgb, var(--accent) 65%, transparent);
}
@container (max-width: 1100px) {
  .wrapper-exec-kpi-band .kpis { grid-template-columns: repeat(3, minmax(0, 1fr)); }
}
@container (max-width: 640px) {
  .wrapper-exec-kpi-band .kpis { grid-template-columns: repeat(2, minmax(0, 1fr)); }
}
@container (max-width: 380px) {
  .wrapper-exec-kpi-band .kpis { grid-template-columns: 1fr; }
}
@media (prefers-reduced-motion: reduce) {
  .wrapper-exec-kpi-band .kpi { transition: none; }
  .wrapper-exec-kpi-band .kpi:hover { transform: none; }
}
